sql:
SELECT COUNT(tag_id) AS tag_count
   FROM model_tags
   WHERE model_id = 1;

external_knowledge:
- "top-ranking models by performance" refers to models with the highest accuracy;
- "three best models per project" means selecting the models with the top three accuracy scores within each project;
- The ranking is determined based on the accuracy metric, with higher values indicating better performance.

sql:
SELECT AVG(accuracy) AS average_accuracy
FROM performance_metrics
WHERE evaluation_timestamp >= strftime('%Y-%m-%d', 'now', '-1 month');

SELECT COUNT(*) AS active_model_versions
FROM model_versions
WHERE version_status = 'active';

SELECT model_id, accuracy
FROM performance_metrics
WHERE accuracy = (SELECT MAX(accuracy) FROM performance_metrics);
